import React, { useState } from 'react';
import StudentManager from './components/StudentManager';
import MovieManager from './components/MovieManager';
import './App.css';

function App() {
  const [activeTab, setActiveTab] = useState('movies');

  return (
    <div className="min-h-screen bg-slate-900">
      {/* Header */}
      <header className="bg-gradient-to-r from-slate-800 to-slate-900 border-b border-yellow-500/20 sticky top-0 z-50 shadow-lg">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-20">
            <div className="flex items-center gap-3">
              <span className="text-4xl">🎬</span>
              <h1 className="text-3xl font-bold bg-gradient-to-r from-yellow-400 to-yellow-600 bg-clip-text text-transparent">
                CineHub
              </h1>
            </div>
            
            {/* Navigation Tabs */}
            <nav className="flex gap-4">
              <button
                onClick={() => setActiveTab('movies')}
                className={`px-6 py-2 rounded-lg font-semibold transition-all duration-300 ${
                  activeTab === 'movies'
                    ? 'bg-yellow-500 text-slate-900 shadow-lg shadow-yellow-500/50'
                    : 'text-gray-300 hover:bg-slate-700 hover:text-white'
                }`}
              >
                🎬 Movies
              </button>
              <button
                onClick={() => setActiveTab('students')}
                className={`px-6 py-2 rounded-lg font-semibold transition-all duration-300 ${
                  activeTab === 'students'
                    ? 'bg-yellow-500 text-slate-900 shadow-lg shadow-yellow-500/50'
                    : 'text-gray-300 hover:bg-slate-700 hover:text-white'
                }`}
              >
                👥 Students
              </button>
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {activeTab === 'movies' && <MovieManager />}
        {activeTab === 'students' && <StudentManager />}
      </main>
    </div>
  );
}

export default App;
